```typescript
// tests/e2e/critical-paths/agent-management.spec.ts
import { test, expect } from '@playwright/test';

test.describe('Agent Management Critical Path', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/');
    // Login
    await page.fill('[data-testid="email"]', 'test@example.com');
    await page.fill('[data-testid="password"]', 'testpassword');
    await page.click('[data-testid="login-button"]');
    await page.waitForURL('/dashboard');
  });

  test('should create, view, and restart an agent', async ({ page }) => {
    // Navigate to agents
    await page.click('[data-testid="nav-agents"]');
    await expect(page).toHaveURL('/agents');

    // Create new agent
    await page.click('[data-testid="create-agent"]');
    await page.fill('[data-testid="agent-name"]', 'E2E Test Agent');
    await page.selectOption('[data-testid="agent-type"]', 'assistant');
    await page.click('[data-testid="submit-agent"]');

    // Verify agent appears in list
    await expect(page.locator('[data-testid="agent-card"]').filter({ hasText: 'E2E Test Agent' })).toBeVisible();

    // View agent details
    await page.click('[data-testid="agent-card"]', { hasText: 'E2E Test Agent' });
    await expect(page.locator('h1')).toHaveText('E2E Test Agent');

    // Restart agent
    await page.click('[data-testid="restart-agent"]');
    await expect(page.locator('[data-testid="agent-status"]')).toHaveText('restarting');

    // Wait for agent to be running again
    await expect(page.locator('[data-testid="agent-status"]')).toHaveText('running', { timeout: 30000 });
  });

  test('should view real-time session output', async ({ page }) => {
    await page.goto('/sessions/test-session');

    // Verify WebSocket connection
    await expect(page.locator('[data-testid="connection-status"]')).toHaveText('connected');

    // Verify output is streaming
    const initialCount = await page.locator('[data-testid="output-line"]').count();
    await page.waitForTimeout(2000);
    const newCount = await page.locator('[data-testid="output-line"]').count();
    expect(newCount).toBeGreaterThan(initialCount);
  });
});
