// tests/visual/components.spec.ts
import { test, expect } from '@playwright/test';

test.describe('Visual Regression Tests', () => {
  test('Dashboard should match snapshot', async ({ page }) => {
    await page.goto('/dashboard');
    await page.waitForLoadState('networkidle');

    // Hide dynamic content for stable snapshots
    await page.evaluate(() => {
      document.querySelectorAll('[data-testid="timestamp"]').forEach(el => {
        el.textContent = '2024-01-01 00:00:00';
      });
    });

    await expect(page).toHaveScreenshot('dashboard.png', {
      maxDiffPixels: 100,
      threshold: 0.2,
    });
  });

  test('Agent Card states should match snapshots', async ({ page }) => {
    await page.goto('/storybook/agent-card');

    // Test different states
    for (const state of ['running', 'stopped', 'error', 'starting']) {
      await page.click(`[data-state="${state}"]`);
      await expect(page.locator('[data-testid="agent-card"]')).toHaveScreenshot(`agent-card-${state}.png`);
    }
  });

  test('Mobile layout should match snapshot', async ({ page }) => {
    await page.setViewportSize({ width: 375, height: 812 }); // iPhone X
    await page.goto('/dashboard');
    await page.waitForLoadState('networkidle');

    await expect(page).toHaveScreenshot('dashboard-mobile.png');
  });
});
